// Parsear topic: ingenio/{finca_id}/{node_id}/up
const parts = msg.topic.split('/');
const finca_id = parts[1];
const node_id  = parts[2];
const tipo     = parts[3];

if (tipo !== 'up') return null;

const payload = msg.payload;
const ts = payload.ts ? payload.ts * 1000 : Date.now();

msg.payload = [
  {
    soil_moisture: payload.soil_moisture || payload.soilMoisture || 0,
    temperature:   payload.temperature   || 0,
    ph:            payload.ph            || payload.pH           || 0,
    nitrogen:      payload.nitrogen      || 0,
    phosphorus:    payload.phosphorus    || 0,
    potassium:     payload.potassium     || 0,
    battery:       payload.battery       || 0,
    rssi:          payload.rssi          || 0,
    time:          ts
  },
  {
    finca_id: finca_id,
    node_id:  node_id
  }
];

msg.measurement = 'sensor_data';

// Pasar el payload original para evaluación de alertas
msg._raw = payload;
msg._finca = finca_id;
msg._node  = node_id;

return msg;

const raw    = msg._raw || {};
const finca  = msg._finca || 'f01';
const nodeId = msg._node  || 's001';
const hum    = raw.soil_moisture || raw.soilMoisture;
const bat    = raw.battery;

// Debounce — no repetir misma alerta en 5 min
const now = Date.now();
if (!context.alertas) context.alertas = {};
const key = `${nodeId}_hum`;
const lastAlert = context.alertas[key] || 0;
if (now - lastAlert < 300000) return null; // 5 minutos

let alerta = null;

if (hum != null && hum < 25) {
    alerta = {type:'crit', node:nodeId, field:'soil_moisture', value:hum,
      msg:`🚨 Humedad crítica en ${nodeId} (${hum.toFixed(1)}%) — Regar urgente`};
} else if (hum != null && hum < 40) {
    alerta = {type:'warn', node:nodeId, field:'soil_moisture', value:hum,
      msg:`💧 Humedad baja en ${nodeId} (${hum.toFixed(1)}%) — Regar hoy`};
}

if (bat != null && bat < 20) {
    const keyBat = `${nodeId}_bat`;
    const lastBat = context.alertas[keyBat] || 0;
    if (now - lastBat > 300000) {
        context.alertas[keyBat] = now;
        alerta = {type:'crit', node:nodeId, field:'battery', value:bat,
          msg:`🔋 Batería crítica en ${nodeId} (${bat.toFixed(0)}%) — Revisar panel solar`};
    }
}

if (!alerta) return null;

context.alertas[key] = now;
msg.topic   = `ingenio/${finca}/alertas`;
msg.payload = alerta;
return msg;
